import React, { useEffect } from 'react'
import './styles.css'
import useProgressBarStore from './useProgressBarStore'

function ProgressBar({ id, idx }) {
    const { progressBars, completeProgressBar } = useProgressBarStore((state) => state)

    function runProgressBar() {
        const progressBar = document.querySelector('.progress-bar')
        let totalWidth = 100
        let width = 0
        let rafId

        function updateWidth() {
            if (width < totalWidth) {
                width += 1
                progressBar.style.width = width + '%'
                rafId = requestAnimationFrame(updateWidth)
            } else {
                completeProgressBar(id)
            }
        }

        rafId = requestAnimationFrame(updateWidth)
        return () => cancelAnimationFrame(rafId)
    }
    useEffect(() => {
        console.log('progressBars', progressBars)
        console.log(progressBars.find(pb => pb.idx === idx - 1))
        // if (progressBars && progressBars.find(pb => pb.idx === idx - 1)[0].completed) {

        // }
        if (progressBars.length > 1 && progressBars.find(pb => pb.idx === idx - 1).completed) {
            runProgressBar()
        }
    }, [id, progressBars])

    useEffect(() => {
        runProgressBar()
    }, [])

    return (
        <>
            <div className="progress-bar-container">
                <div className='progress-bar'></div>
            </div>
        </>
    )
}

export default ProgressBar
